import type { ComponentProps, ComponentRef } from 'react';
import { Timer as TimerPrimitive } from '@ark-ui/react/timer';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Timer.module.css';

const TimerRoot = forwardRef<
  ComponentRef<typeof TimerPrimitive.Root>,
  ComponentProps<typeof TimerPrimitive.Root>
>(function TimerRoot({ className, ...props }, ref) {
  return (
    <TimerPrimitive.Root
      ref={ref}
      data-slot="timer-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const TimerRootProvider = forwardRef<
  ComponentRef<typeof TimerPrimitive.RootProvider>,
  ComponentProps<typeof TimerPrimitive.RootProvider>
>(function TimerRootProvider({ className, ...props }, ref) {
  return (
    <TimerPrimitive.RootProvider
      ref={ref}
      data-slot="timer-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const TimerArea = forwardRef<
  ComponentRef<typeof TimerPrimitive.Area>,
  ComponentProps<typeof TimerPrimitive.Area>
>(function TimerArea({ className, ...props }, ref) {
  return (
    <TimerPrimitive.Area
      ref={ref}
      data-slot="timer-area"
      className={clsx(styles.area, normalizeClassName(className))}
      {...props}
    />
  );
});

const TimerItem = forwardRef<
  ComponentRef<typeof TimerPrimitive.Item>,
  ComponentProps<typeof TimerPrimitive.Item>
>(function TimerItem({ className, ...props }, ref) {
  return (
    <TimerPrimitive.Item
      ref={ref}
      data-slot="timer-item"
      className={clsx(styles.item, normalizeClassName(className))}
      {...props}
    />
  );
});

const TimerSeparator = forwardRef<
  ComponentRef<typeof TimerPrimitive.Separator>,
  ComponentProps<typeof TimerPrimitive.Separator>
>(function TimerSeparator({ className, ...props }, ref) {
  return (
    <TimerPrimitive.Separator
      ref={ref}
      data-slot="timer-separator"
      className={clsx(styles.separator, normalizeClassName(className))}
      {...props}
    />
  );
});

const TimerControl = forwardRef<
  ComponentRef<typeof TimerPrimitive.Control>,
  ComponentProps<typeof TimerPrimitive.Control>
>(function TimerControl({ className, ...props }, ref) {
  return (
    <TimerPrimitive.Control
      ref={ref}
      data-slot="timer-control"
      className={clsx(styles.control, normalizeClassName(className))}
      {...props}
    />
  );
});

const TimerActionTrigger = forwardRef<
  ComponentRef<typeof TimerPrimitive.ActionTrigger>,
  ComponentProps<typeof TimerPrimitive.ActionTrigger>
>(function TimerActionTrigger({ className, ...props }, ref) {
  return (
    <TimerPrimitive.ActionTrigger
      ref={ref}
      data-slot="timer-action-trigger"
      className={clsx(styles.actionTrigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const Timer = Object.assign(TimerRoot, {
  Root: TimerRoot,
  RootProvider: TimerRootProvider,
  Area: TimerArea,
  Item: TimerItem,
  Separator: TimerSeparator,
  Control: TimerControl,
  ActionTrigger: TimerActionTrigger,
});

export { Timer };

@layer ui.components {
  .root {
    box-sizing: border-box;
    display: inline-grid;
    place-items: center;
    gap: var(--timer-gap, var(--spacing-3));
    width: var(--timer-width, max-content);
    color: var(--timer-color, var(--color-foreground));
  }

  .area {
    display: inline-flex;
    align-items: baseline;
    gap: var(--timer-area-gap, var(--spacing-1));
    font-size: var(--timer-area-font-size, var(--text-2xl));
    font-weight: var(--timer-area-font-weight, var(--weight-semibold));
    line-height: var(--timer-area-line-height, var(--line-height-text-sm));
    font-variant-numeric: tabular-nums;
    letter-spacing: 0;
  }

  .item {
    min-width: var(--timer-item-min-width, 2ch);
    color: var(--timer-item-color, currentColor);
    text-align: var(--timer-item-text-align, center);
  }

  .separator {
    color: var(--timer-separator-color, var(--color-muted-foreground));
  }

  .control {
    display: inline-flex;
    flex-wrap: wrap;
    align-items: center;
    gap: var(--timer-control-gap, var(--spacing-2));
  }

  .actionTrigger {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: var(--timer-action-trigger-gap, var(--spacing-2));
    min-height: var(--timer-action-trigger-height, var(--size-md));
    margin: 0;
    border: var(--timer-action-trigger-border-width, var(--border-width-sm)) solid
      var(--timer-action-trigger-border-color, var(--color-border));
    border-radius: var(--timer-action-trigger-radius, var(--radius-md));
    padding-block: var(--timer-action-trigger-padding-y, 0.375rem);
    padding-inline: var(--timer-action-trigger-padding-x, 0.75rem);
    background-color: var(--timer-action-trigger-bg, var(--color-background));
    color: var(--timer-action-trigger-color, var(--color-foreground));
    appearance: none;
    font: inherit;
    font-size: var(--timer-action-trigger-font-size, var(--text-sm));
    font-weight: var(--timer-action-trigger-font-weight, var(--weight-medium));
    line-height: var(--timer-action-trigger-line-height, var(--line-height-text-sm));
    white-space: nowrap;
    cursor: pointer;
    transition:
      background-color var(--timer-action-trigger-transition, var(--transition-default)),
      border-color var(--timer-action-trigger-transition, var(--transition-default)),
      color var(--timer-action-trigger-transition, var(--transition-default)),
      opacity var(--timer-action-trigger-transition, var(--transition-default)),
      box-shadow var(--timer-action-trigger-transition, var(--transition-default));

    @media (hover: hover) {
      &:hover {
        background-color: var(--timer-action-trigger-bg-hover, var(--color-accent));
      }
    }

    &:focus-visible {
      outline: var(--timer-action-trigger-focus-ring-width, var(--border-width-md)) solid
        var(--timer-action-trigger-focus-ring-color, var(--color-ring));
      outline-offset: var(--timer-action-trigger-focus-ring-offset, -1px);
    }

    &:is(:disabled, [aria-disabled='true']) {
      opacity: var(--timer-action-trigger-disabled-opacity, var(--opacity-disabled));
      cursor: default;
      pointer-events: none;
    }

    &[hidden] {
      display: none;
    }

    & :where(svg) {
      width: var(--timer-action-trigger-icon-size, 1rem);
      height: var(--timer-action-trigger-icon-size, 1rem);
      flex-shrink: 0;
    }
  }
}
